3_real_world_example.code:
// --- module: counter.js (conceptual) ---
let count = 0;

function increment() {
  count++; // 'count' is from THIS file's scope — always
  return count;
}

// --- caller (anywhere in the app) ---
// Even called from a different file/module, 'increment' still
// accesses 'count' from the module where it was DEFINED.
console.log(increment()); // 1
console.log(increment()); // 2

// Proof: lexical, not dynamic
let count = 999; // a 'count' in the caller's scope
increment();     // still uses the module's 'count' (now 3), not 999

6_edge_case.code:
const obj = {
  name: 'SkillSprint',
  // Regular function: 'this' is dynamic — set by call site
  greetRegular: function() {
    setTimeout(function() {
      console.log(this.name); // undefined — 'this' inside setTimeout is global
    }, 100);
  },
  // Arrow function: 'this' is lexical — captured from obj's method
  greetArrow: function() {
    setTimeout(() => {
      console.log(this.name); // 'SkillSprint'  — lexical 'this'
    }, 100);
  }
};
obj.greetArrow();
